import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'react-hot-toast';
import { AuthProvider, useAuth } from './context/AuthContext';

import Navbar      from './components/Navbar';
import Footer      from './components/Footer';
import Home        from './pages/Home';
import Services    from './pages/Services';
import Plans       from './pages/Plans';
import Booking     from './pages/Booking';
import MyBookings  from './pages/MyBookings';
import Login       from './pages/Login';
import Register    from './pages/Register';
import AdminDashboard from './pages/admin/Dashboard';
import Review from './pages/Review';
import './index.css';

const queryClient = new QueryClient({
  defaultOptions: { queries: { retry: 1, staleTime: 1000 * 60 * 2 } },
});

// Protected route wrapper
const ProtectedRoute = ({ children, adminOnly = false }) => {
  const { user, loading } = useAuth();
  if (loading) return <div style={{ padding: '120px', textAlign: 'center' }}>Loading...</div>;
  if (!user) return <Navigate to="/login" replace />;
  if (adminOnly && user.role !== 'admin') return <Navigate to="/" replace />;
  return children;
};

const AppContent = () => (
  <>
    <Navbar />
    <Routes>
      <Route path="/"          element={<Home />} />
      <Route path="/services"  element={<Services />} />
      <Route path="/plans"     element={<Plans />} />
      <Route path="/login"     element={<Login />} />
      <Route path="/register"  element={<Register />} />
      <Route path="/book"      element={<ProtectedRoute><Booking /></ProtectedRoute>} />
      <Route path="/my-bookings" element={<ProtectedRoute><MyBookings /></ProtectedRoute>} />
      <Route path="/admin"     element={<ProtectedRoute adminOnly><AdminDashboard /></ProtectedRoute>} />
      <Route path="*"          element={<Navigate to="/" replace />} />
    </Routes>
    <Footer />
  </>
);

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <Router>
          <Toaster position="top-right" toastOptions={{ duration: 3500, style: { fontFamily: 'DM Sans', fontSize: '13px' } }} />
          <AppContent />
        </Router>
      </AuthProvider>
    </QueryClientProvider>
  );
}
